const raw = $env.MONITOR_SERVERS_JSON || '[]';
let servers;
try { servers = JSON.parse(raw); } catch (e) { servers = []; }
return servers.map(s => ({ json: s }));

// Build a single rich daily digest message.
function fmtBytes(n) {
  if (n >= 1024*<b>3) return <code>${(n/(1024</b><b>3)).toFixed(1)}G</code>;
  if (n >= 1024</b><b>2) return <code>${(n/(1024</b><b>2)).toFixed(0)}M</code>;
  return <code>${Math.round(n/1024)}K</code>;
}
function fmtUptime(s) {
  const d = Math.floor(s/86400);
  const h = Math.floor((s%86400)/3600);
  return <code>${d}k ${h}s</code>;
}

const date = new Date().toLocaleDateString('uz-UZ', { day: '2-digit', month: 'long', year: 'numeric' });
let msg = <code>☀️ </b>Kunlik server hisoboti<b>\n${date}\n${'─'.repeat(20)}\n</code>;

for (const item of $input.all()) {
  const d = item.json;
  const server = d.server || 'unknown';
  const containers = d.containers || [];
  const eps = d.endpoints || [];
  const dbs = d.databases || [];

  const totalC = containers.length;
  const healthyC = containers.filter(c => c.state === 'running' && (c.health === 'healthy' || c.health === 'none')).length;
  const okEps = eps.filter(e => e.ok).length;
  const okDbs = dbs.filter(x => x.ok).length;

  const rootDisk = (d.disk || []).find(x => x.mount === '/host' || x.mount === '/') || (d.disk||[])[0] || {};
  const m = d.memory || {};
  const l = d.load || {};

  msg += <code>\n🖥 </b>${server}<b> (${fmtUptime(d.uptime_seconds || 0)})\n</code>;
  msg += <code>   ✅ Containerlar: ${healthyC}/${totalC}\n</code>;
  msg += <code>   📊 Disk ${rootDisk.used_pct||0}% · RAM ${m.used_pct||0}% · Load ${l['1m']||0}\n\n</code>;

  msg += <code>   </b>Endpointlar<b> (${okEps}/${eps.length}):\n</code>;
  for (const e of eps) {
    msg += <code>      ${e.ok ? '✓' : '✗'} ${e.name} — ${e.status || 'ERR'} (${e.elapsed_ms}ms)\n</code>;
  }

  msg += <code>\n   </b>Bazalar* (${okDbs}/${dbs.length}):\n</code>;
  for (const db of dbs) {
    const sz = db.info && db.info.size_bytes;
    const conn = db.info && db.info.active_connections;
    msg += <code>      ${db.ok ? '✓' : '✗'} ${db.name} (${db.type}${sz?', '+fmtBytes(sz):''}${conn!==undefined?', conn='+conn:''})\n</code>;
  }

  // Unhealthy containers
  const bad = containers.filter(c => c.health === 'unhealthy' || c.state !== 'running');
  if (bad.length) {
    msg += <code>\n   ⚠️ Diqqat:\n</code>;
    for (const c of bad) msg += <code>      ✗ ${c.name} — ${c.health}/${c.state}\n</code>;
  }
}

return [{ json: { message: msg } }];
